commands.handler:
function (args) {
  var valid = ['google', 'airbnb', 'standard', 'pep8', 'effective-go'];
  if (!args || args.length === 0) {
    output.print('Current style: ' + state.get(stateKeys.style));
    output.print('Available: ' + valid.join(', '));
    return;
  }
  var s = args[0].toLowerCase();
  if (valid.indexOf(s) === -1) {
    output.print('Unknown style: ' + s);
    output.print('Available: ' + valid.join(', '));
    return;
  }
  state.set(stateKeys.style, s);
  output.print('Style set to: ' + s);
}

function (args) {
  if (!args || args.length === 0) {
    output.print('Current language: ' + state.get(stateKeys.language));
    return;
  }
  state.set(stateKeys.language, args[0].toLowerCase());
  output.print('Language set to: ' + args[0].toLowerCase());
}
